    import org.json.JSONArray;
    import org.json.JSONObject; 
    import sailpoint.object.Identity;
    import org.apache.commons.logging.Log;
    import org.apache.commons.logging.LogFactory;
    
    private static Log logger = LogFactory.getLog("sailpoint.services.asc.Gsuite"); 
        
    public String returnValue(Object value){
        if(void == value || value == null){
          logger.debug("Returning null");
          return "";
        }
        else{
          logger.debug("Returning value: " + value.toString());
          return value.toString();
        }
    }
        
    List phonesList = new ArrayList();

    String[] phoneNumberTypes =  {"work", "work_mobile", "work_fax", "home", "work_pager", "custom"};
    String[] phoneNumberIdentityAttribute =  {"telephoneNumber","mobile","facsimileTelephoneNumber","homePhone","pager","googleVoiceNumber"};
    JSONArray phoneJSONArray = new JSONArray();
    for(int count = 0; count < phoneNumberTypes.length; count++){
      JSONObject eachJSONObject = new JSONObject();
      if(identity.getAttribute(phoneNumberIdentityAttribute[count]) != null){
        logger.debug("Evaluating: " + phoneNumberTypes[count]);
        if("work".equalsIgnoreCase(phoneNumberTypes[count])){
          eachJSONObject.put("primary",true);
          eachJSONObject.put("type",phoneNumberTypes[count]);
          eachJSONObject.put("value",returnValue(identity.getAttribute(phoneNumberIdentityAttribute[count])));
        } else if("custom".equalsIgnoreCase(phoneNumberTypes[count])){
		  eachJSONObject.put("primary",false);
          eachJSONObject.put("type",phoneNumberTypes[count]);
		  eachJSONObject.put("customType","Google Voice");
          eachJSONObject.put("value",returnValue(identity.getAttribute(phoneNumberIdentityAttribute[count])));
		} else{
          eachJSONObject.put("primary",false);
          eachJSONObject.put("type",phoneNumberTypes[count]);
          eachJSONObject.put("value",returnValue(identity.getAttribute(phoneNumberIdentityAttribute[count])));
        }
        phonesList.add(eachJSONObject.toString());  
      }
    }

    logger.debug("Returning phonesList: " + phonesList);
    return phonesList;
